        { "Description", "\240\159\147\157 \"Many projectile weapons now no longer benefit from the auto-latency-redirection system. This system used to redirect projectiles in an effort to make high ping play more enjoyable\"" },
        { "Description", "\240\159\147\157 \"Most weapons now no longer reset their simpler cooldowns on equip, such as shooting a gun. This means that strategies such as Sniper + Fists are no longer abuseable\"" },
        { "Description", "\240\159\147\157 \"Semi-automatic weapons now benefit from \"input queueing\" \226\128\148 shooting while on cooldown will queue the input to go through as soon as the cooldown is lifted, resulting in more consistent shots & DPS\"" },
        { "Header", "Assault Rifle" },
        { "Description", "\240\159\147\157 \"The recent firerate nerf made the Assault Rifle not as enjoyable to play, we\'re shifting the nerf to a different metric\"" },
        { "Description", "\240\159\148\187 Damage decreased from 13 \226\134\146 12" },
        { "Description", "\240\159\146\170 Shoot cooldown decreased from 0.11s \226\134\146 0.1s" },
        { "Header", "Bow" },
        { "Description", "\240\159\147\157 \"The Bow\'s high charge damage and high mobility encouraged frustrating, passive gameplay\"" },
        { "Description", "\240\159\148\187 Charge damage changed from (50% / 100% / 150% / 240%) \226\134\146 (100% / 125% / 150% / 200%)" },
        { "Header", "Grenade Launcher" },
        { "Description", "\240\159\147\157 \"The Grenade Launcher\'s splash damage has been underwhelming\"" },
        { "Description", "\240\159\146\170 Splash damage increased from 35 \226\134\146 40" },
        { "Description", "\240\159\146\170 Projectiles are no longer affected by auto-latency-redirection" },
        { "Header", "Gunblade" },
        { "Description", "\240\159\147\157 \"Relying on landing 2 headshots with gun mode has held the Gunblade back\"" },
        { "Description", "\240\159\146\170 Gun body damage increased from 40 \226\134\146 45" },
        { "Description", "\240\159\146\170 Gun critical damage increased from 50 \226\134\146 55" },
        { "Description", "\240\159\155\160 No longer fires a shot after landing a blade attack that doesn\'t deal any damage (e.g. against a Riot Shield)" },
        { "Description", "\240\159\155\160 No longer fires a shot after landing a blade attack that eliminates enemies (e.g. against windows & low health enemies)" },
        { "Header", "Minigun" },
        { "Description", "\240\159\147\157 \"To keep the Minigun\'s high raw damage, we\'ve decided to make it less effective at range\"" },
        { "Description", "\240\159\148\187 Shoot spread increased from 1.5\194\176 \226\134\146 2\194\176" },
        { "Description", "\240\159\148\187 ADS shoot spread increased from 0\194\176 \226\134\146 1\194\176" },
        { "Header", "Paintball Gun" },
        { "Description", "\240\159\147\157 \"The Paintball Gun dealt too much total damage in a single magazine\"" },
        { "Description", "\240\159\148\187 Max ammo decreased from 20 \226\134\146 16" },
        { "Description", "\240\159\146\170 Max ammo reserve increased from 20 \226\134\146 24" },
        { "Header", "RPG" },
        { "Description", "\240\159\147\157 \"It was too easy to dodge the RPG\'s rockets in the current high-mobility meta\"" },
        { "Description", "\240\159\146\170 Projectile speed increased from 75studs/s \226\134\146 100studs/s" },
        { "Description", "\240\159\146\170 Projectiles are no longer affected by auto-latency-redirection" },
        { "Header", "Shotgun" },
        { "Description", "\240\159\147\157 \"These changes will help the Shotgun feel more satisfying and consistent with each shot\"" },
        { "Description", "\240\159\146\170 Shoot spread decreased from 10\194\176 \226\134\146 5\194\176" },
        { "Description", "\240\159\148\187 Damage dropoff introduced" },
        { "Description", "\240\159\155\160 Shooting while aiming now automatically stops aiming" },
        { "Header", "Sniper" },
        { "Description", "\240\159\147\157 \"This strategy was extremely unfair to play against\"" },
        { "Description", "\240\159\148\187 Can no longer bypass the shoot cooldown by quick meleeing with Fists (other weapons suffer the same change but the Sniper has been most affected by this)" },
        { "Header", "Daggers" },
        { "Description", "\240\159\147\157 \"The recent nerfs to the Daggers were too harsh\"" },
        { "Description", "\240\159\146\170 Body damage increased from 15 \226\134\146 20" },
        { "Header", "Energy Pistols" },
        { "Description", "\240\159\147\157 \"As mentioned before, secondaries should feel reliable enough to quickly switch to\"" },
        { "Description", "\240\159\146\170 Equip cooldown decreased from 0.85s \226\134\146 0.45s" },
        { "Header", "Flare Gun" },
        { "Description", "\240\159\147\157 \"The Flare Gun\'s damage has simply been not enough\"" },
        { "Description", "\240\159\146\170 DPS increased from 40 \226\134\146 50" },
        { "Header", "Handgun" },
        { "Description", "\240\159\147\157 \"Input Queueing should make the Handgun feel more consistent\"" },
        { "Description", "\240\159\146\170 Now benefits from input queueing" },
        { "Header", "Revolver" },
        { "Description", "\240\159\147\157 \"The Revolver\'s quick equip provided no weaknesses to this high damage secondary\"" },
        { "Description", "\240\159\148\187 Equip cooldown increased from 0.45s \226\134\146 0.7s" },
        { "Header", "Shorty" },
        { "Description", "\240\159\147\157 \"These changes will help the Shorty feel more satisfying and consistent with each shot\"" },
        { "Description", "\240\159\146\170 Shoot spread decreased from 15\194\176 \226\134\146 7.5\194\176" },
        { "Description", "\240\159\148\187 Damage dropoff introduced" },
        { "Description", "\240\159\146\170 Now benefits from input queueing" },
        { "Header", "Slingshot" },
        { "Description", "\240\159\147\157 \"While the Slingshot has been in a more balanced state, we want Slingshot players that can actually aim to feel rewarded\"" },
        { "Description", "\240\159\146\170 Critical damage increased from 7.5 \226\134\146 9" },
        { "Header", "Spray" },
        { "Description", "\240\159\147\157 \"The Spray should feel like a reliable sidearm that you can quickly switch to\"" },
        { "Description", "\240\159\146\170 Shoot cooldown decreased from 0.4s \226\134\146 0.3s" },
        { "Header", "Battle Axe" },
        { "Description", "\240\159\147\157 \"The Battle Axe not only dealt too much damage too easily, but the knockback would also set up free eliminations way too easily\"" },
        { "Description", "\240\159\148\187 Spin damage decreased from 40 \226\134\146 30" },
        { "Description", "\240\159\148\187 Spin knockback reduced by 50%" },
        { "Header", "Chainsaw" },
        { "Description", "\240\159\147\157 \"The Chainsaw\'s ability struggles to compete against other melee options\"" },
        { "Description", "\240\159\146\170 Ability move speed bonus increased from +75% \226\134\146 +85%" },
        { "Description", "\240\159\146\170 Max ammo increased from 100 \226\134\146 150" },
        { "Header", "Fists" },
        { "Description", "\240\159\147\157 \"This strategy was extremely unfair to play against\"" },
        { "Description", "\240\159\148\187 Can no longer bypass attack cooldowns via quick meleeing" },
        { "Header", "Knife" },
        { "Description", "\240\159\147\157 \"The Knife should feel like a quick, nimble weapon\"" },
        { "Description", "\240\159\146\170 Equip cooldown decreased from 1s \226\134\146 0.45s" },
        { "Header", "Flashbang" },
        { "Description", "\240\159\147\157 \"The Flashbang\'s high blind duration has always been a problem, especially when 2 can be thrown at once\"" },
        { "Description", "\240\159\148\187 Blind duration decreased from 4s \226\134\146 3s" },
        { "Header", "Freeze Ray" },
        { "Description", "\240\159\147\157 \"This small change should result in more consistent shots\"" },
        { "Description", "\240\159\146\170 Projectiles are no longer affected by auto-latency-redirection" },
        { "Header", "Jump Pad" },
        { "Description", "\240\159\147\157 \"Jump Pads should be usable for entire rounds\"" },
        { "Description", "\240\159\146\170 Lifetime increased from 60s \226\134\146 90s" },
        { "Header", "Medkit" },
        { "Description", "\240\159\147\157 \"The Medkit offers too much value for how easy it is to use\"" },
        { "Description", "\240\159\148\187 Full heal amount decreased from 75 \226\134\146 70" },
        { "Description", "\240\159\148\187 Quick heal amount decreased from 30 \226\134\146 25" },
        { "Description", "\240\159\146\170 Can no longer be interrupted by damage over time (e.g. fire damage)" },
